import { useContext } from 'react';

import { iconStyle } from './Icon.sty.js';
import { _sanitizeSymbol as sanitizeSymbol } from '../../../../../core/utils/sanitize-symbol.js';
import { SingleValueContext } from '../contexts/single-value.context.js';

export const Icon = () => {
  const { prefixIcon } = useContext(SingleValueContext);
  const isString = typeof prefixIcon === 'string';

  return prefixIcon ? (
    <div className={iconStyle({ isString })}>
      {isString ? sanitizeSymbol(prefixIcon) : prefixIcon}
    </div>
  ) : null;
};

Icon['displayName'] = 'SingleValue.Icon';
